var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 저희가 여기 온 건 마도구에 마력을 충전하기 위해서겠네요?","JPN":"じゃあ私たちがここに来たのは、魔道具に魔力を補充するためなんですね？","ENG":"So are we here to recharge the staff with mana?","TWN":"那我們來到這裡就是為了給魔導具填充魔力？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네, 정답~","JPN":"そう、正解～！","ENG":"Bingo!","TWN":"沒錯，答對了~"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇지만 오늘 온 데에는 다른 이유도 있어.","JPN":"でも今日ここに来たのには別の理由もあるわ。","ENG":"But there's another reason why we're here today.","TWN":"但我們今天來這裡還有另外一個理由。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"얼마 안 있으면 열릴 특별한 이벤트를 준비해야 하거든.","JPN":"もうじき開かれる特別なイベントの準備があるの。","ENG":"We need to prepare for a special event that's coming up.","TWN":"為即將舉辦的特殊活動做準備。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"특별한 이벤트요?","JPN":"特別なイベント？","ENG":"A special event?","TWN":"特殊活動？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래, 조금 있으면 할로윈 축제 날이잖니?","JPN":"そう、もうすぐハロウィンパーティーでしょう？","ENG":"That's right. It's going to be Halloween soon, you know?","TWN":"嗯，萬聖節慶典不是快到了嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"맞다...... 요즘 정신이 없어서 까맣게 잊고 있었어요.","JPN":"本当だ……最近忙しくてすっかり忘れてました。","ENG":"Oh, right... I completely forgot about it with everything that's happened.","TWN":"對哦……我都忘了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리 가게에서 만든 할로윈 코스튬은 이 도시에서 꽤 유명하거든.","JPN":"うちの店で作ったハロウィンコスチュームは、この都市でもかなり有名なの。","ENG":"The Halloween costumes we sell are a hit in this city.","TWN":"我們店裡做的萬聖節服裝在這個城市裡可是很有名的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"올해도 주문이 잔뜩 들어왔는데 기한을 맞추려면 오늘 내로 재료를 충분히 모아야 해.","JPN":"今年も注文が殺到してるから、期限に間に合わせるには今日中に材料を揃えないといけないわ。","ENG":"We've received a whole lot of orders this year, too. If we want to meet the deadlines, we have to collect the materials by the end of today.","TWN":"今年也接到了很多訂單，想按時交貨，就要在今天內收集足夠的材料。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어라? 코스튬 만드는 데 쓸 재료를 이런 데에서 구해요?","JPN":"え？　コスチュームを作る材料をこんな所で探すんですか？","ENG":"Huh? You mean you get the materials for your costumes in a place like this?","TWN":"啊？服裝材料為什麼要在這裡找？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗, 혹시......!","JPN":"あっ、もしかして……！","ENG":"Oh, you mean...","TWN":"啊，難道……？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"딩동댕~ 우리가 만드는 코스튬은 마녀의 비술을 곁들인 일종의 기능성 제품이야.","JPN":"ピンポ～ン！　私たちが作るコスチュームは、魔女の秘術を使った一種の機能性製品なの。","ENG":"That's right! Our costumes are actually somewhat functional, as they're imbued with witch magic.","TWN":"答對了~我們做的服裝是融入魔女秘術的功能性產品。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래서 제작하는 데에도 특별한 마법의 재료들이 필요하거든.","JPN":"だから、製作するのにも特別な魔法の材料が必要よ。","ENG":"That's why they require special, magical materials to make them.","TWN":"所以製作的時候需要一些特殊的魔法材料。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이 곳은 우리가 그런 다양한 마법 재료들을 구하는 장소이기도 하단다.","JPN":"ここは、私たちがいろんな魔法の材料を手に入れる場所でもあるわ。","ENG":"This is where we procure all sorts of magic ingredients for that.","TWN":"而這裡可以收集到各種魔法材料。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......그 재료들이라는 게 혹시 침식체한테서 얻는 건가요?","JPN":"……その材料って、まさか侵食体から入手するんですか？","ENG":"Um, you don't happen to get those materials from Corrupted Objects, do you?","TWN":"……妳說的那些材料，是從侵蝕體身上得來的嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 잘 이해했네. 가르치는 보람이 있는걸?","JPN":"ふふっ。察しが良いわね。教え甲斐があるわ。","ENG":"Hah hah, you're a quick learner. I think I'm going to enjoy teaching you.","TWN":"哈哈，妳理解的沒錯，孺子可教也！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러니까 힘내렴~ 침식체에게 잡아 먹히지 않게 조심하고~","JPN":"だから頑張ってね～。侵食体に食べられないように気をつけて。","ENG":"So buckle up, kid. Try not to let those C.O.s eat you!","TWN":"那妳加油吧~小心不要被侵蝕體吃了~"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};